/* polymyth-horoscope-archetypes-set3.js
 * Set 3: Mesopotamian (12), Burmese (8), Mayan (20), Aztec (20), Hebrew (12), Vedic (27).
 */

(function(global) {
  'use strict';

  if (!global.PolymythHoroscopeArchetypes) global.PolymythHoroscopeArchetypes = {};
  var A = global.PolymythHoroscopeArchetypes;

  // ============================================================
  // MESOPOTAMIAN (12 Babylonian deity-signs)
  // ============================================================
  A['mesopotamian-enki'] = { name:'Enki (Goat-Fish, Freshwater-Wisdom)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"God of the freshwater abyss, of crafts, of wisdom that flows like underground rivers. Enki archetype carries: technical intelligence, capacity to work with hidden resources, the figure who knows how things actually function beneath official explanations. Themes of cleverness in the service of life, the trickster who saves humanity from the flood. Shadow side: the figure whose knowledge becomes private property, the engineer who makes things only they can repair." };
  A['mesopotamian-gula'] = { name:'Gula (the Healer)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Healing goddess, dog-companioned, mistress of medicines. Gula archetype carries: practical capacity to mend, the figure whose hands work on broken bodies, the medicine-knowledge passed by mother to daughter. Themes of the bedside, the figure who is summoned when everything has gone wrong. Shadow side: the figure whose role is so defined by others' damage they cannot exist without it." };
  A['mesopotamian-nina'] = { name:'Nina (Fish-Mother)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Goddess of the deep waters, fish-mother, dream-interpreter. Nina archetype carries: intuitive intelligence operating below surface registers, capacity to read symbols and omens, the figure who navigates by feel rather than landmark. Themes of dreaming, oracular knowledge, the figure who fishes meaning from depth. Shadow side: the figure who is so attuned to depths they cannot function in the shallows where most life happens." };
  A['mesopotamian-shamash'] = { name:'Shamash (Sun-King of Justice)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Sun-god, judge of the gods and of mortals, the figure whose light makes things visible to be judged. Shamash archetype carries: ethical clarity, the figure whose presence forces honesty, justice as illumination rather than punishment. Themes of public reckoning, the courtroom-of-the-sun. Shadow side: the figure whose clarity becomes severity, the judge who has forgotten how anyone arrived at their actions." };
  A['mesopotamian-inanna-bull'] = { name:'Inanna and the Bull-of-Heaven', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Inanna unleashed the Bull of Heaven on Gilgamesh's city when he refused her love. The Taurus-equivalent in this tradition is the figure of unleashed power held in living-flesh form. Carries themes of fertility, royal anger, the bull as compressed potential. Shadow side: the figure whose strength is deployed in revenge for slights that did not warrant the strength's full release." };
  A['mesopotamian-gilgamesh'] = { name:'Gilgamesh (Twin-Hero)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"The hero-king with his wild-born twin Enkidu — the friendship-pair as the load-bearing relation of the epic. Gilgamesh archetype carries: heroic ambition tempered by grief, the figure who seeks immortality and learns mortality, the bond with the unlike-other as transformative. Themes of friendship as the deeper love, the journey to the world's edge. Shadow side: the figure whose questing becomes its own end, the king who cannot stop seeking long enough to rule." };
  A['mesopotamian-gula-lulim'] = { name:'Lulim (Stag-of-the-Temple)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"The temple-stag, sacred animal of the boundary between forest and city. Lulim archetype carries: dignified retreat, the figure whose authority is also their gentleness, capacity to be protective without aggressive display. Themes of the sanctuary-keeper, the figure whose territory is consecrated rather than conquered. Shadow side: the figure whose retreat becomes default, the stag who flees before testing whether the danger was real." };
  A['mesopotamian-nergal'] = { name:'Nergal (Lion-King-of-the-Underworld)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Plague god, war god, eventual ruler of the underworld through marriage to Ereshkigal. Nergal archetype carries: forceful charisma in service of the underworld's necessities, the figure who handles death's domain with imperial bearing. Themes of marriage-as-conquest-and-transformation, lion-as-king-of-darkness. Shadow side: the figure whose force becomes pure dominion, the king whose realm is what he destroyed." };
  A['mesopotamian-shala'] = { name:'Shala (Grain-Maiden)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Grain goddess, harvest-bringer, wife of the storm-god Adad. Shala archetype carries: agricultural intelligence, the figure whose nurture is the literal food-source, capacity to be the sustaining-presence behind the more dramatic figure. Themes of fertility tied to actual labor, the maiden-with-the-sheaf. Shadow side: the figure whose labor is invisible until it stops, the provider taken for granted." };
  A['mesopotamian-zibanitu'] = { name:'Zibanitu (Scales-of-Judgment)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"The balance-scales constellation, predecessor of the Greek Libra. Zibanitu archetype carries: judicial intelligence, capacity to weigh competing claims without picking a side prematurely, the figure who is asked to decide. Themes of arbitration, the courtroom-instrument as symbolic of the kind of mind needed. Shadow side: the figure whose weighing becomes paralysis, the scales that cannot settle." };
  A['mesopotamian-gir-tab'] = { name:'Gir-tab (Scorpion-Watchman)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Scorpion-people guard the gates of the sun in the Gilgamesh epic — terrifying-but-just sentinels at thresholds of cosmic significance. Gir-tab archetype carries: capacity to stand at the threshold, intelligence at the boundary between domains, the figure whose terrifying appearance hides actual fairness. Themes of the gate-keeper-as-tester, intimidation in service of legitimate inquiry. Shadow side: the figure whose threshold-position becomes obstruction, the guard who has forgotten what passes through." };
  A['mesopotamian-pabilsag'] = { name:'Pabilsag (Centaur-Archer)', tradition:'Mesopotamian/Babylonian zodiac', writeup:"Half-human, half-beast archer-figure — predecessor of Sagittarius. Pabilsag archetype carries: dual-nature intelligence, capacity to operate in both civilized and wild registers, aim that requires the body's animal-knowledge as much as the mind's calculation. Themes of the hybrid as superior to either pure form, the figure who shoots at horizons. Shadow side: the figure whose dual nature becomes neither-fully — neither animal enough nor civilized enough." };

  // ============================================================
  // BURMESE (8 weekday-planet-animal signs, Wednesday split AM/PM)
  // ============================================================
  A['burmese-sun-garuda'] = { name:'Sunday: Sun / Garuda', tradition:'Burmese astrology (Mahabote)', writeup:"Sunday-born under the Sun, sigil-animal Garuda — the celestial bird-king from Hindu and Buddhist iconography. Carries themes of: leadership, brilliance, capacity to rise above conflict, the figure whose presence makes others stand straighter. Garuda is enemy of serpents (the figures of low cunning), so Sun-born are mythologically opposed to manipulative-types. Shadow side: pride, the figure whose elevation becomes distance from the people they were meant to lead." };
  A['burmese-moon-tiger'] = { name:'Monday: Moon / Tiger', tradition:'Burmese astrology (Mahabote)', writeup:"Monday-born under the Moon, sigil-animal Tiger. The Moon brings interiority and emotional intelligence; the Tiger brings solitary power. The combination is the figure who is fierce but private, whose strength is held in reserve and revealed only when conditions require it. Carries themes of patience, the figure who reads the room from a quiet position before acting. Shadow side: moodiness that becomes its own weather, the tiger who becomes unreadable to those who depend on them." };
  A['burmese-mars-lion'] = { name:'Tuesday: Mars / Lion', tradition:'Burmese astrology (Mahabote)', writeup:"Tuesday-born under Mars, sigil-animal Lion. Mars brings warrior-energy; the Lion brings royal authority. The figure is the king-as-warrior, leadership-through-courage, the figure others rally around in conflict. Carries themes of righteous action, the willingness to defend the chosen people physically. Shadow side: aggression as default, the figure whose readiness for fight summons fights." };
  A['burmese-mercury-elephant'] = { name:'Wednesday morning: Mercury / Tusked Elephant', tradition:'Burmese astrology (Mahabote)', writeup:"Wednesday-AM-born under Mercury, sigil-animal Tusked Elephant. Mercury brings intelligence and verbal facility; the tusked-elephant brings dignified strength and excellent memory. The figure is the wise elder before they have aged into the role, the diplomat with reserves of force. Carries themes of careful communication, the figure who is trusted with delicate negotiations. Shadow side: the figure whose long memory becomes grudge-keeping." };
  A['burmese-rahu-elephant'] = { name:'Wednesday afternoon: Rahu / Tuskless Elephant', tradition:'Burmese astrology (Mahabote)', writeup:"Wednesday-PM-born under Rahu (the eclipse-shadow), sigil-animal Tuskless Elephant. Rahu is the disrupting force; the tuskless-elephant is the working-elephant, all power without ornamental display. The figure is the unflashy heavy-lifter, the worker whose contribution is foundational rather than decorative. Carries themes of unassuming strength, the figure who carries the weight others cannot. Shadow side: invisibility, the figure whose lack of display becomes lack of recognition." };
  A['burmese-jupiter-rat'] = { name:'Thursday: Jupiter / Rat', tradition:'Burmese astrology (Mahabote)', writeup:"Thursday-born under Jupiter, sigil-animal Rat. Jupiter brings expansion and good fortune; the Rat brings cunning resourcefulness. The figure is fortunate AND clever, the lucky one who also did the work to deserve the luck. Carries themes of teaching, abundance, the figure who shares what they have because they trust more is coming. Shadow side: presumption, the figure who confuses good fortune with their own merit." };
  A['burmese-venus-guinea-pig'] = { name:'Friday: Venus / Guinea-Pig', tradition:'Burmese astrology (Mahabote)', writeup:"Friday-born under Venus, sigil-animal Guinea-Pig. Venus brings love and beauty; the guinea-pig brings sociable warmth and gentle presence. The figure is the friend-everyone-wants, the social glue, the figure whose presence makes the room more affectionate. Carries themes of sweetness without saccharine, the figure who creates safe spaces for others' tenderness. Shadow side: people-pleasing as substitute for actual position." };
  A['burmese-saturn-naga'] = { name:'Saturday: Saturn / Naga (Serpent-Spirit)', tradition:'Burmese astrology (Mahabote)', writeup:"Saturday-born under Saturn, sigil-animal Naga — the serpent-spirit of Buddhist and Hindu iconography, water-spirit and treasure-keeper. Saturn brings discipline and time; the Naga brings depth, ancient knowledge, and connection to underground waters. The figure is the keeper of long traditions, the figure whose patience is generations long. Carries themes of esoteric knowledge, the figure who holds what should not be exposed prematurely. Shadow side: melancholy, the figure whose long view becomes pessimism." };

  // ============================================================
  // MAYAN TZOLKIN (20 day-signs)
  // ============================================================
  A['mayan-imix'] = { name:'Imix (Crocodile / Earth-Mother)', tradition:'Mayan tzolkin', writeup:"First day-sign — the primordial mother, the earth-as-creature, the dragon-of-beginnings. Imix archetype carries: foundational creativity, capacity to begin from nothing, the figure who provides the substrate others build on. Themes of fertility, the floating-island that became the world. Shadow side: the figure who is so foundational they cannot move when the structure built on them needs them to shift." };
  A['mayan-ik'] = { name:'Ik (Wind / Breath / Spirit)', tradition:'Mayan tzolkin', writeup:"Wind-sign, breath-sign, the invisible animating force. Ik archetype carries: communicative intelligence, capacity to move ideas across distances, the figure whose presence brings life into static situations. Themes of inspiration in the literal Latin sense (in-breathing), the messenger-spirit. Shadow side: scattered-ness, the wind that cannot stay long enough to become weather." };
  A['mayan-akbal'] = { name:'Akbal (Night / Underworld)', tradition:'Mayan tzolkin', writeup:"Night-sign, the underworld, the dream. Akbal archetype carries: capacity to operate in dark conditions, intelligence that requires absence-of-distraction, the figure who knows what others cannot bear to look at. Themes of the dream-vigil, the night-watch, the inner world. Shadow side: the figure who confuses depth-of-shadow with depth-of-soul, melancholy as identity." };
  A['mayan-kan'] = { name:'Kan (Lizard / Seed / Generative-Energy)', tradition:'Mayan tzolkin', writeup:"Seed-sign, lizard-sign — the principle of generation, of stored-potential waiting for the right conditions. Kan archetype carries: latent power, capacity to hold form across time, the figure whose patience preserves what would otherwise be lost. Themes of fertility, sexual energy, the inheritor. Shadow side: the figure whose latency becomes their permanent state, the seed that does not germinate." };
  A['mayan-chicchan'] = { name:'Chicchan (Serpent / Life-Force)', tradition:'Mayan tzolkin', writeup:"Serpent-sign — the life-force itself, the kundalini-equivalent in Mesoamerican thought. Chicchan archetype carries: intense vital energy, capacity for transformation, the figure whose presence is electric. Themes of the snake-deity, sexual-spiritual force, the body as conduit. Shadow side: intensity that consumes, the figure who cannot regulate the current they channel." };
  A['mayan-cimi'] = { name:'Cimi (Death / Transformation)', tradition:'Mayan tzolkin', writeup:"Death-sign — the transition, the ending-as-beginning. Cimi archetype carries: capacity to handle endings without flinching, the figure who can sit with loss, transformation-through-letting-go. Themes of the psychopomp, the figure who guides others through dissolution. Shadow side: the figure who hurries others' endings, who confuses their own comfort with closure." };
  A['mayan-manik'] = { name:'Manik (Deer / Hand)', tradition:'Mayan tzolkin', writeup:"Deer-sign, hand-sign — the principle of grasping and of graceful motion. Manik archetype carries: practical capacity, the figure whose hands solve what minds cannot, healing-touch intelligence. Themes of accomplishment through skill, the artisan, the surgeon. Shadow side: the figure whose hands are always working becomes incapable of rest." };
  A['mayan-lamat'] = { name:'Lamat (Rabbit / Star / Venus)', tradition:'Mayan tzolkin', writeup:"Rabbit-and-Venus sign — the morning star, the principle of beauty-through-multiplication. Lamat archetype carries: aesthetic intelligence, fecundity in creative output, the figure whose abundance is the gift. Themes of art, fertility, the dawn-bringer. Shadow side: scattered output, the figure whose many starts become no completions." };
  A['mayan-muluc'] = { name:'Muluc (Water / Offering)', tradition:'Mayan tzolkin', writeup:"Water-sign, offering-sign — the principle of ritual giving, of what flows. Muluc archetype carries: emotional intelligence, capacity for sacrifice that is not loss but exchange, the figure whose generosity is structural. Themes of the offering-bowl, water-as-purification, the gift-economy. Shadow side: the figure whose giving becomes obligation, the offering that cannot be refused." };
  A['mayan-oc'] = { name:'Oc (Dog / Loyalty)', tradition:'Mayan tzolkin', writeup:"Dog-sign — the loyalty-principle, the companion. Oc archetype carries: faithful presence, capacity to stay through what others abandon, the figure whose love is unconditional. Themes of companionship, the guide in the underworld (Mayan dogs led souls to the afterlife), the partnership. Shadow side: dependency, the figure whose loyalty extends to people no longer worth it." };
  A['mayan-chuen'] = { name:'Chuen (Monkey / Artisan)', tradition:'Mayan tzolkin', writeup:"Monkey-sign — the artisan, the trickster, the maker. Chuen archetype carries: creative intelligence, capacity for play that is also work, the figure whose mischief is also craft. Themes of artistry, weaving, the spider-monkey as god of the arts. Shadow side: the figure whose play prevents seriousness, the artisan who never finishes." };
  A['mayan-eb'] = { name:'Eb (Road / Journey / Grass)', tradition:'Mayan tzolkin', writeup:"Road-sign, journey-sign — the path itself, the principle of progress through traversal. Eb archetype carries: capacity for sustained travel, the figure whose life is structured as journey, pilgrim-intelligence. Themes of the road as teacher, the figure who is shaped by what they pass through. Shadow side: the figure who cannot stop, who confuses motion with direction." };
  A['mayan-ben'] = { name:'Ben (Reed / Cornstalk)', tradition:'Mayan tzolkin', writeup:"Reed-sign, cornstalk-sign — the principle of upright-growth, of straightness as virtue. Ben archetype carries: principled posture, capacity to be a pillar in the household, the figure whose integrity is structural. Themes of the home as cosmic axis, ancestral continuity. Shadow side: rigidity, the figure whose principles become inflexibility." };
  A['mayan-ix'] = { name:'Ix (Jaguar / Earth-Spirit)', tradition:'Mayan tzolkin', writeup:"Jaguar-sign — the earth-spirit, the night-power, the shaman's animal. Ix archetype carries: magical capacity, intelligence that operates in altered states, the figure whose power comes from earth-contact. Themes of the shamanic vocation, transformation, the priest-warrior. Shadow side: the figure whose specialness becomes isolation, the shaman who has forgotten their community." };
  A['mayan-men'] = { name:'Men (Eagle / Vision)', tradition:'Mayan tzolkin', writeup:"Eagle-sign — the high-vision principle, capacity to see the whole field. Men archetype carries: strategic intelligence, the figure who sees what others miss because of altitude, leadership-through-perspective. Themes of the watcher, the figure on the heights. Shadow side: the figure whose elevation becomes coldness, the eagle who has stopped descending." };
  A['mayan-cib'] = { name:'Cib (Owl / Vulture / Wisdom-of-the-Dead)', tradition:'Mayan tzolkin', writeup:"Owl-and-vulture sign — the wisdom that comes from contact with the dead, the elder-knowledge. Cib archetype carries: ancestral intelligence, capacity to channel what previous generations knew, the figure who consults the dead. Themes of the seer, the lineage-bearer, the figure who is older than they are. Shadow side: the figure whose ancestor-orientation becomes refusal of the present." };
  A['mayan-caban'] = { name:'Caban (Earth / Earthquake / Movement)', tradition:'Mayan tzolkin', writeup:"Earth-sign, earthquake-sign — the principle of large-scale movement, of when the ground itself shifts. Caban archetype carries: capacity to instigate large change, intelligence that operates at structural scale, the figure who moves the ground others stand on. Themes of revolution, paradigm-shift, the architect of upheaval. Shadow side: the figure whose movements destroy what they could have reformed." };
  A['mayan-etznab'] = { name:'Etznab (Flint / Mirror / Knife)', tradition:'Mayan tzolkin', writeup:"Flint-sign, mirror-sign, knife-sign — the principle of clarification through cutting, of truth-as-reflection. Etznab archetype carries: discrimination, capacity to cut through illusion, the figure whose mirror reveals what others avoid seeing. Themes of the obsidian blade, the surgical mind. Shadow side: cutting that becomes habitual, the figure who has nothing left to cut and starts on themselves." };
  A['mayan-cauac'] = { name:'Cauac (Storm / Rain)', tradition:'Mayan tzolkin', writeup:"Storm-sign — the principle of cleansing-through-deluge, of necessary upheaval. Cauac archetype carries: transformative force, capacity to bring the rain that ends the drought, the figure whose disruption is also gift. Themes of weather as moral force, the storm-bringer. Shadow side: chaos for its own sake, the figure who confuses their own intensity with necessity." };
  A['mayan-ahau'] = { name:'Ahau (Lord / Sun / Flower)', tradition:'Mayan tzolkin', writeup:"Lord-sign, sun-sign, flower-sign — the final day-sign, the completion-principle. Ahau archetype carries: completed authority, the figure who has arrived, sovereignty as flower-rather-than-fortress. Themes of mastery, the late-stage arrival at one's vocation, the figure who blooms. Shadow side: the figure whose completion becomes stasis, the lord who has stopped becoming." };

  // ============================================================
  // AZTEC TONALPOHUALLI (20 day-signs, Nahuatl names — parallel structure to Mayan)
  // ============================================================
  A['aztec-cipactli'] = { name:'Cipactli (Crocodile / Earth-Monster)', tradition:'Aztec tonalpohualli', writeup:"First day-sign — the primordial crocodile-earth-monster from whose body the world was made by Tezcatlipoca. Cipactli archetype carries: foundational power, the figure whose generative capacity is also their consumption-capacity, primordial multiplicity. Themes of beginnings, fertility-from-violence, the figure who founds dynasties. Shadow side: appetite without limit, the figure whose hunger consumed what it created." };
  A['aztec-ehecatl'] = { name:'Ehecatl (Wind / Breath)', tradition:'Aztec tonalpohualli', writeup:"Wind-sign — Quetzalcoatl in his wind-aspect, the breath-of-the-gods. Ehecatl archetype carries: invisible animating presence, capacity to inspire (in the Latin sense), the figure who moves things without being seen to move them. Themes of communication, the spiral-shape (Ehecatl's temples were round), inspiration as physical-spiritual force. Shadow side: the figure who moves so subtly their effects are denied or attributed elsewhere." };
  A['aztec-calli'] = { name:'Calli (House)', tradition:'Aztec tonalpohualli', writeup:"House-sign — domestic order, the principle of containment, the structured-interior. Calli archetype carries: capacity to build the holding-space, intelligence operating in the architecture of family-life, the figure whose home is everyone's refuge. Themes of hospitality, structural care, the household as cosmos-in-miniature. Shadow side: the figure whose house becomes their entire world, the home as fortress against everything outside." };
  A['aztec-cuetzpalin'] = { name:'Cuetzpalin (Lizard)', tradition:'Aztec tonalpohualli', writeup:"Lizard-sign — agility, regeneration, the figure who can lose a tail and regrow it. Cuetzpalin archetype carries: adaptive intelligence, capacity to survive what would destroy others through flexibility, the figure who renews after damage. Themes of resilience, opportunism in the productive sense. Shadow side: the figure whose agility becomes inability to commit, who is always prepared to leave." };
  A['aztec-coatl'] = { name:'Coatl (Serpent)', tradition:'Aztec tonalpohualli', writeup:"Serpent-sign — Quetzalcoatl-energy, the wisdom-animal, the figure who sheds skins. Coatl archetype carries: transformation through periodic letting-go, esoteric knowledge, the figure whose continuity is achieved through repeated re-becoming. Themes of the spiritual-philosophical lineage, sacred kingship. Shadow side: the figure whose transformations become evasions, who sheds before fully inhabiting." };
  A['aztec-miquiztli'] = { name:'Miquiztli (Death)', tradition:'Aztec tonalpohualli', writeup:"Death-sign — Mictlantecuhtli's day, the underworld-king. Miquiztli archetype carries: capacity to dwell with what others flee, the figure who handles last-rites, intimate knowledge of dissolution. Themes of the funeral, the threshold-keeper of the afterlife, the wisdom that comes from looking at death without flinching. Shadow side: the figure who is so familiar with death they bring it into living-spaces prematurely." };
  A['aztec-mazatl'] = { name:'Mazatl (Deer)', tradition:'Aztec tonalpohualli', writeup:"Deer-sign — gentleness, sacrifice (deer were sacrificial animals in Aztec ritual), woodland-grace. Mazatl archetype carries: noble bearing, capacity for gentle strength, the figure whose grace is also their vulnerability. Themes of the woodland, the noble sacrifice, the sensitive presence. Shadow side: passivity, the figure whose gentleness becomes inability to defend their territory." };
  A['aztec-tochtli'] = { name:'Tochtli (Rabbit)', tradition:'Aztec tonalpohualli', writeup:"Rabbit-sign — fertility, drunkenness, the moon-animal. Aztec '400 rabbits' were the gods of pulque (fermented drink). Tochtli archetype carries: capacity for joy, fertility, the celebrant. Themes of intoxication as sacred state, the multiplication-of-pleasures. Shadow side: the figure whose celebrations become escapes, the rabbit-multiplier who breeds problems faster than solutions." };
  A['aztec-atl'] = { name:'Atl (Water)', tradition:'Aztec tonalpohualli', writeup:"Water-sign — Chalchiuhtlicue's day, the goddess of streams and lakes. Atl archetype carries: emotional intelligence, capacity to flow around obstacles, the figure whose nurture is foundational. Themes of cleansing, the source-of-life, the figure who softens stone over time. Shadow side: the figure who flows so well they take the shape of every container without being any of them." };
  A['aztec-itzcuintli'] = { name:'Itzcuintli (Dog)', tradition:'Aztec tonalpohualli', writeup:"Dog-sign — Xolotl, the underworld-guide, dogs were buried with the dead in Aztec practice to lead them across the river of the afterlife. Itzcuintli archetype carries: companionable loyalty, capacity to guide through difficult passages, the figure whose presence makes thresholds passable. Themes of the psychopomp, faithful companionship. Shadow side: the figure whose loyalty includes following into territories where loyalty is no longer wisdom." };
  A['aztec-ozomatli'] = { name:'Ozomatli (Monkey)', tradition:'Aztec tonalpohualli', writeup:"Monkey-sign — playfulness, the arts, the figure whose work looks like play. Ozomatli archetype carries: creative wit, capacity for spontaneous making, the figure whose levity is also discipline. Themes of dance, music, crafts. Shadow side: the figure whose play becomes deflection, who turns serious moments into jokes to avoid them." };
  A['aztec-malinalli'] = { name:'Malinalli (Grass / Brush)', tradition:'Aztec tonalpohualli', writeup:"Grass-sign — the principle of persistence-through-cutting, the herb that grows back. Malinalli archetype carries: tenacity, capacity to recover from being cut down, the figure whose root-system is always larger than what is visible. Themes of recovery, regeneration, healing herbs. Shadow side: stubbornness, the figure who keeps regenerating in places where they were not wanted." };
  A['aztec-acatl'] = { name:'Acatl (Reed)', tradition:'Aztec tonalpohualli', writeup:"Reed-sign — Tezcatlipoca's day, the principle of straightness, reeds-as-arrows-and-pipes. Acatl archetype carries: principled directness, capacity to be the arrow-shaft of someone else's intention or one's own, the figure whose value is structural. Themes of the warrior, the messenger, the architect-of-cosmic-order. Shadow side: rigidity, the figure who confuses their own straightness with the only correct posture." };
  A['aztec-ocelotl'] = { name:'Ocelotl (Jaguar)', tradition:'Aztec tonalpohualli', writeup:"Jaguar-sign — the warrior-cult animal, the spotted-night-hunter. Ocelotl archetype carries: solitary power, capacity for night-work, the figure whose strength is also their secrecy. Themes of the warrior-priest, jungle-intelligence, the predator who hunts alone. Shadow side: isolation, the figure whose self-sufficiency becomes loneliness they cannot admit." };
  A['aztec-cuauhtli'] = { name:'Cuauhtli (Eagle)', tradition:'Aztec tonalpohualli', writeup:"Eagle-sign — the warrior-cult companion to the jaguar, the sun-bird. Cuauhtli archetype carries: high-altitude vision, capacity for strategic overview, the figure who sees the field whole from above. Themes of the eagle-warrior order, leadership, the sun's descent at the horizon. Shadow side: the figure whose elevation becomes detachment from the ground-level realities of those they lead." };
  A['aztec-cozcacuauhtli'] = { name:'Cozcacuauhtli (Vulture)', tradition:'Aztec tonalpohualli', writeup:"Vulture-sign — the elder-bird, the figure who outlives multiple generations, the death-cleaner. Cozcacuauhtli archetype carries: longevity, capacity to handle others' remainders without judgment, ancient-knowledge held in patient bodies. Themes of the elder-counselor, the figure who has seen everything before. Shadow side: cynicism, the figure whose long view becomes contempt for new attempts." };
  A['aztec-ollin'] = { name:'Ollin (Movement / Earthquake)', tradition:'Aztec tonalpohualli', writeup:"Movement-sign — the principle of cosmic motion, the day-sign associated with the current age (the Fifth Sun, doomed to end in earthquakes). Ollin archetype carries: capacity for self-directed change, intelligence that operates through transformation, the figure whose stability comes through movement rather than stasis. Themes of the dance, the heart-as-engine, the unfolding-of-time. Shadow side: the figure whose movement becomes restlessness, the dance that cannot stop." };
  A['aztec-tecpatl'] = { name:'Tecpatl (Flint)', tradition:'Aztec tonalpohualli', writeup:"Flint-knife sign — the sacrificial blade, the principle of sharp-clarification through cutting. Tecpatl archetype carries: discriminating intelligence, capacity to make the cut that releases what was trapped, the figure whose precision is in service of larger transformation. Themes of the obsidian, surgical clarity, the ritual specialist. Shadow side: cutting as habit, the figure whose every solution is the blade." };
  A['aztec-quiahuitl'] = { name:'Quiahuitl (Rain)', tradition:'Aztec tonalpohualli', writeup:"Rain-sign — Tlaloc's day, the rain-god of the Mexica. Quiahuitl archetype carries: capacity for emotional storms that nourish, the figure whose intensity is also fertility, weather-as-gift. Themes of the rain-priest, agricultural blessing, the storm-as-sacrament. Shadow side: emotional flooding, the figure whose rain drowns those they meant to feed." };
  A['aztec-xochitl'] = { name:'Xochitl (Flower)', tradition:'Aztec tonalpohualli', writeup:"Flower-sign — Xochiquetzal's day, the goddess of love, flowers, and beauty. Final day-sign of the cycle. Xochitl archetype carries: aesthetic intelligence as cosmic principle, capacity to make the world more beautiful by presence, the figure whose contribution is the flowering. Themes of art, courtship, the flower-song poetry of Aztec literature. Shadow side: the figure whose beauty becomes their only offering, decoration without substance." };

  // ============================================================
  // HEBREW MONTH-SIGNS (12, with tribal associations from Sefer Yetzirah)
  // ============================================================
  A['hebrew-tishrei-libra'] = { name:'Tishrei / Libra / Tribe of Ephraim', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Tishrei is the month of Rosh Hashanah and Yom Kippur — the new year and day of atonement. The figure born under Tishrei carries: capacity for honest self-accounting, judicial intelligence, the figure who weighs the year. Tribal correspondence: Ephraim, Joseph's son, the favored one. Themes of beginnings-through-reckoning, balance, the courtroom of the soul. Shadow side: the figure whose self-judgment becomes harsher than any external judge could be." };
  A['hebrew-cheshvan-scorpio'] = { name:'Cheshvan / Scorpio / Tribe of Manasseh', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Cheshvan is the only Hebrew month with no holidays — known as 'mar Cheshvan' (bitter Cheshvan). The figure born under Cheshvan carries: capacity to dwell with absence, intelligence that operates without celebration-cues, the figure who works the unrewarded ground. Tribal correspondence: Manasseh, Joseph's elder son. Themes of the unmarked stretch, depth-work in plain time. Shadow side: the figure whose preference for unmarked time becomes refusal to celebrate when celebration is appropriate." };
  A['hebrew-kislev-sagittarius'] = { name:'Kislev / Sagittarius / Tribe of Benjamin', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Kislev is the month of Hanukkah, the festival of light in winter darkness. The figure born under Kislev carries: capacity to bring light into dark conditions, faith-as-action, the figure whose hope is also their tactic. Tribal correspondence: Benjamin, the youngest son of Jacob. Themes of miracles in small quantities, the lamp-oil that lasted, perseverance. Shadow side: the figure whose optimism becomes denial of how dark it actually got." };
  A['hebrew-tevet-capricorn'] = { name:'Tevet / Capricorn / Tribe of Dan', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Tevet is mid-winter, the deepest cold. The figure born under Tevet carries: capacity for sustained discipline, intelligence that operates through hardship, the figure whose work is structural and slow. Tribal correspondence: Dan, the judge-tribe. Themes of judgment, the long view, what can be built only when the field is bare. Shadow side: severity, the figure whose discipline becomes coldness." };
  A['hebrew-shevat-aquarius'] = { name:'Shevat / Aquarius / Tribe of Asher', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Shevat contains Tu BiShvat, the new year of the trees — life moving under winter ground. The figure born under Shevat carries: capacity to perceive what is happening invisibly, faith in the unseen process, the figure who plants knowing the harvest is years away. Tribal correspondence: Asher, blessed with abundance. Themes of underground vitality, ecological intelligence, the long-time perspective. Shadow side: the figure whose attention to the underground becomes neglect of the visible above-ground." };
  A['hebrew-adar-pisces'] = { name:'Adar / Pisces / Tribe of Naphtali', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Adar is the month of Purim, the festival of reversal where mourning turns to joy. The figure born under Adar carries: capacity for transformation through reversal, comedic intelligence, the figure whose deepest seriousness arrives wrapped in carnival. Tribal correspondence: Naphtali, the swift one. Themes of hidden providence, the Esther-figure operating within the king's house, joy-as-resistance. Shadow side: the figure who hides behind the carnival mask permanently." };
  A['hebrew-nisan-aries'] = { name:'Nisan / Aries / Tribe of Judah', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Nisan is the month of Passover, the spring liberation, the founding-month of the Hebrew calendar. The figure born under Nisan carries: capacity for liberatory leadership, the figure whose voice is needed at the founding moment, kingly bearing. Tribal correspondence: Judah, the tribe of David, the messianic line. Themes of exodus, the new beginning, the figure whose 'let my people go' starts history. Shadow side: the figure whose foundational role becomes inability to share the founding." };
  A['hebrew-iyar-taurus'] = { name:'Iyar / Taurus / Tribe of Issachar', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Iyar is the wilderness-month, the time of healing after the exodus. The figure born under Iyar carries: capacity for steady work in the in-between, healing intelligence, the figure whose patience makes recovery possible. Tribal correspondence: Issachar, the scholar-tribe known for understanding the times. Themes of medicinal time, the manna-period, the figure who knows when. Shadow side: the figure whose patience becomes passivity in the face of conditions that need acting on." };
  A['hebrew-sivan-gemini'] = { name:'Sivan / Gemini / Tribe of Zebulun', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Sivan is the month of Shavuot, the giving of the Torah at Sinai. The figure born under Sivan carries: capacity to receive and transmit the foundational text, twin-tongued intelligence (the Torah-interpretation tradition operates in dialectic), the figure whose communication is sacred-bearing. Tribal correspondence: Zebulun, the merchant-tribe associated with seafaring and exchange. Themes of revelation, study, exchange-of-meaning. Shadow side: the figure who studies endlessly without ever practicing what was studied." };
  A['hebrew-tammuz-cancer'] = { name:'Tammuz / Cancer / Tribe of Reuben', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Tammuz contains the breaching of Jerusalem's walls — the beginning of the three-week mourning period. The figure born under Tammuz carries: capacity to feel the breach when it happens, emotional intelligence at large historical scale, the figure who mourns properly. Tribal correspondence: Reuben, the firstborn who lost his birthright. Themes of grief-work, the ruptured wall, the home that was. Shadow side: the figure whose mourning becomes their identity, who cannot stop being the one-who-grieves." };
  A['hebrew-av-leo'] = { name:'Av / Leo / Tribe of Simeon', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Av contains Tisha B'Av, the day commemorating the Temple's destruction. The figure born under Av carries: capacity to hold loss without it crushing them, leonine dignity in the face of devastation, the figure who survives the burning-down. Tribal correspondence: Simeon, the second son. Themes of the destroyed temple, the work of carrying-on, the dignity of the displaced. Shadow side: the figure whose dignity-in-loss becomes refusal to ever rebuild." };
  A['hebrew-elul-virgo'] = { name:'Elul / Virgo / Tribe of Gad', tradition:'Hebrew month-tribe correspondence (Sefer Yetzirah)', writeup:"Elul is the month of preparation for the high holidays, the time of selichot (forgiveness-prayers) and self-examination. The figure born under Elul carries: capacity for sustained self-review, analytical intelligence applied to one's own conduct, the figure whose precision is internal. Tribal correspondence: Gad, the warrior-tribe. Themes of the king-in-the-field (Elul is when 'the king is in the field' per Hasidic teaching — the divine accessible without formality). Shadow side: the figure whose self-examination becomes scrupulosity." };

  // ============================================================
  // VEDIC NAKSHATRAS (27 — Sun-position approximation in v1; full jyotish requires moon-position with ephemeris)
  // ============================================================
  A['vedic-ashwini'] = { name:'Ashwini (the Horse-Twins)', tradition:'Vedic nakshatra (Sun-approximation, v1)', writeup:"First nakshatra — the divine physician twins, the Ashvins. Ashwini archetype carries: speed in healing, capacity to arrive first when help is needed, dawn-energy. Themes of pioneering, restorative intelligence, the figure who shows up when others are still on the way." };
  A['vedic-bharani'] = { name:'Bharani (the Bearer)', tradition:'Vedic nakshatra', writeup:"Second nakshatra — Yama, lord of death and dharma. Bharani archetype carries: capacity to bear what others cannot, judicial intelligence about what is owed, the figure who handles birth-and-death thresholds. Themes of restraint, transformation through endurance, the ethical responsibility of carrying." };
  A['vedic-krittika'] = { name:'Krittika (the Cutter / Pleiades)', tradition:'Vedic nakshatra', writeup:"Third nakshatra — Agni the fire-god, the seven sisters of the Pleiades. Krittika archetype carries: cutting clarity, capacity to separate true from false, fierce nurture (the Krittikas raised the war-god Skanda). Themes of purification through fire, sharp insight, the warrior-mother." };
  A['vedic-rohini'] = { name:'Rohini (the Red One)', tradition:'Vedic nakshatra', writeup:"Fourth nakshatra — Brahma the creator, the favored star of the Moon's wives in myth. Rohini archetype carries: sensual abundance, fertility, the figure whose beauty draws devotion. Themes of creative attraction, growth, the productive-pleasure principle. Shadow side: vanity, the figure whose draw becomes consumption of admirers." };
  A['vedic-mrigashira'] = { name:'Mrigashira (the Deer-Head)', tradition:'Vedic nakshatra', writeup:"Fifth nakshatra — Soma, the moon-god, the deer-shaped constellation. Mrigashira archetype carries: gentle searching, the figure whose curiosity is its own reward, restless intellectual hunger. Themes of the seeker, the figure who follows the scent without knowing the destination." };
  A['vedic-ardra'] = { name:'Ardra (the Moist One / Storm-Star)', tradition:'Vedic nakshatra', writeup:"Sixth nakshatra — Rudra, the storm-god, fierce form of Shiva. Ardra archetype carries: tempestuous transformation, capacity to bring necessary destruction, the figure whose storms clear stale air. Themes of the cleansing tear, intensity that purifies. Shadow side: destructiveness without follow-through, the storm that does not nourish what it watered." };
  A['vedic-punarvasu'] = { name:'Punarvasu (the Return of Light)', tradition:'Vedic nakshatra', writeup:"Seventh nakshatra — Aditi, mother of the gods, the principle of return-and-renewal. Punarvasu archetype carries: capacity for fresh starts after exhaustion, motherly intelligence, the figure who knows how to come back. Themes of the recovered home, second chances, restorative wisdom." };
  A['vedic-pushya'] = { name:'Pushya (the Nourisher)', tradition:'Vedic nakshatra', writeup:"Eighth nakshatra — Brihaspati, Jupiter, teacher of the gods. Considered most auspicious of all nakshatras. Pushya archetype carries: nurturing intelligence, the figure who feeds others' growth, devotional service. Themes of the spiritual teacher, generosity that does not deplete, the cow-mother." };
  A['vedic-ashlesha'] = { name:'Ashlesha (the Embracer / Serpent-Star)', tradition:'Vedic nakshatra', writeup:"Ninth nakshatra — the Nagas, serpent-deities of wisdom and danger. Ashlesha archetype carries: hypnotic intelligence, capacity to mesmerize, the figure whose embrace is also entanglement. Themes of poison-and-medicine, the kundalini, esoteric knowledge. Shadow side: manipulation, the figure whose embrace becomes constriction." };
  A['vedic-magha'] = { name:'Magha (the Mighty / Throne-Star)', tradition:'Vedic nakshatra', writeup:"Tenth nakshatra — the Pitris, the ancestors. Magha archetype carries: ancestral authority, capacity to draw on generational power, the figure who sits on the throne their lineage built. Themes of inheritance, royal bearing, the duty to the dead. Shadow side: the figure whose authority depends entirely on what they inherited rather than what they did." };
  A['vedic-purva-phalguni'] = { name:'Purva Phalguni (the Former Red Fig)', tradition:'Vedic nakshatra', writeup:"Eleventh nakshatra — Bhaga, god of marital bliss and good fortune. Purva Phalguni archetype carries: enjoyment-capacity, the figure who knows how to receive good things, sensual contentment. Themes of marriage, art, the fruit-tree in season. Shadow side: complacency, the figure who stops working once the comfort arrives." };
  A['vedic-uttara-phalguni'] = { name:'Uttara Phalguni (the Latter Red Fig)', tradition:'Vedic nakshatra', writeup:"Twelfth nakshatra — Aryaman, god of contracts and patrons. Uttara Phalguni archetype carries: capacity to honor commitments, the figure whose patronage enables others' work, dignified provision. Themes of the long marriage, the agreement honored across decades, generosity as structural rather than impulsive." };
  A['vedic-hasta'] = { name:'Hasta (the Hand)', tradition:'Vedic nakshatra', writeup:"Thirteenth nakshatra — Savitar, the sun-as-vivifier, the hand-of-creation. Hasta archetype carries: skilled handwork, dexterity in art and healing, the figure who makes things real through their hands. Themes of craft, the closing-the-deal, manual intelligence. Shadow side: the figure whose hands are always busy at the cost of being able to be still." };
  A['vedic-chitra'] = { name:'Chitra (the Brilliant)', tradition:'Vedic nakshatra', writeup:"Fourteenth nakshatra — Tvashtri, the divine architect. Chitra archetype carries: aesthetic genius, capacity to create what is dazzling, the figure whose work shines. Themes of the artist-architect, glamorous magnetism, the gem-cutter. Shadow side: superficiality, the figure whose brilliance is all surface-shine." };
  A['vedic-swati'] = { name:'Swati (the Independent / Sword-Star)', tradition:'Vedic nakshatra', writeup:"Fifteenth nakshatra — Vayu, the wind-god. Swati archetype carries: independent intelligence, the figure who moves freely, diplomatic finesse. Themes of the merchant-traveler, self-determining motion, the figure who answers to no one specific. Shadow side: detachment from any specific community, the figure whose freedom prevents commitment." };
  A['vedic-vishakha'] = { name:'Vishakha (the Forked / Two-Branched)', tradition:'Vedic nakshatra', writeup:"Sixteenth nakshatra — Indra and Agni paired. Vishakha archetype carries: dual-focused ambition, capacity to pursue two paths simultaneously, goal-oriented intensity. Themes of the forked road approached as both rather than either, productive obsession. Shadow side: divided attention, the figure who never fully arrives at either goal." };
  A['vedic-anuradha'] = { name:'Anuradha (the Devoted)', tradition:'Vedic nakshatra', writeup:"Seventeenth nakshatra — Mitra, the god of friendship and contracts. Anuradha archetype carries: devotional intelligence, capacity for sustained loyalty, the figure who builds across time through fidelity. Themes of the long friendship, balance maintained through commitment, the disciple-as-master-of-discipleship." };
  A['vedic-jyeshtha'] = { name:'Jyeshtha (the Eldest)', tradition:'Vedic nakshatra', writeup:"Eighteenth nakshatra — Indra, king of the gods. Jyeshtha archetype carries: senior authority, capacity to take the elder-position, responsibility-bearing. Themes of the eldest sibling, the captain who carries the team, leadership as burden accepted gracefully. Shadow side: the figure whose seniority becomes resentment of those less burdened." };
  A['vedic-mula'] = { name:'Mula (the Root)', tradition:'Vedic nakshatra', writeup:"Nineteenth nakshatra — Nirriti, goddess of dissolution. Mula archetype carries: capacity to investigate to the root, the figure who pulls things up by their origins, philosophical fearlessness. Themes of the spiritual seeker who does not stop at comfortable answers, the surgeon-of-the-soul. Shadow side: destructiveness, the figure who uproots what should have been left to grow." };
  A['vedic-purva-ashadha'] = { name:'Purva Ashadha (the Former Invincible)', tradition:'Vedic nakshatra', writeup:"Twentieth nakshatra — Apas, the waters. Purva Ashadha archetype carries: undefeatable spirit, capacity for inspirational leadership, the figure whose conviction carries others. Themes of the orator, water-deep persistence, the early-stage of unstoppable momentum. Shadow side: the figure whose conviction becomes unwillingness to update on contrary evidence." };
  A['vedic-uttara-ashadha'] = { name:'Uttara Ashadha (the Latter Invincible)', tradition:'Vedic nakshatra', writeup:"Twenty-first nakshatra — the Vishvedevas, the universal-gods. Uttara Ashadha archetype carries: durable victory, capacity to win the long campaign, principled excellence. Themes of integrity that outlasts opposition, the figure whose long-term win is the only kind that mattered. Shadow side: the figure whose long campaigns leave no time for joy along the way." };
  A['vedic-shravana'] = { name:'Shravana (the Hearer)', tradition:'Vedic nakshatra', writeup:"Twenty-second nakshatra — Vishnu the preserver, the listening-ear. Shravana archetype carries: receptive intelligence, capacity to learn through listening, the figure whose wisdom comes from attention. Themes of the student-of-tradition, the keeper-of-stories, scholarship-through-hearing. Shadow side: the figure who listens to so many traditions they cannot find their own voice." };
  A['vedic-dhanishta'] = { name:'Dhanishta (the Wealthy)', tradition:'Vedic nakshatra', writeup:"Twenty-third nakshatra — the Vasus, the elemental gods. Dhanishta archetype carries: musical-rhythmic intelligence, capacity for prosperity that is also generosity, the figure who carries the drum that organizes the dance. Themes of music as cosmic principle, group-rhythm, the figure whose timing harmonizes the others." };
  A['vedic-shatabhisha'] = { name:'Shatabhisha (the Hundred Healers)', tradition:'Vedic nakshatra', writeup:"Twenty-fourth nakshatra — Varuna, god of cosmic waters and oaths. Shatabhisha archetype carries: medical-mystical intelligence, capacity for healing that exceeds standard methods, the figure who works with what is hidden in the body. Themes of esoteric healing, oath-keeping, the figure who is bound by promises others have forgotten." };
  A['vedic-purva-bhadrapada'] = { name:'Purva Bhadrapada (the Former Auspicious One)', tradition:'Vedic nakshatra', writeup:"Twenty-fifth nakshatra — Aja Ekapada, the one-footed serpent. Purva Bhadrapada archetype carries: intense spiritual energy, capacity for fiery transformation, the figure whose practice burns. Themes of the ascetic, the figure who undertakes severe disciplines, transformation through purgation." };
  A['vedic-uttara-bhadrapada'] = { name:'Uttara Bhadrapada (the Latter Auspicious One)', tradition:'Vedic nakshatra', writeup:"Twenty-sixth nakshatra — Ahir Budhnya, the dragon-of-the-deep. Uttara Bhadrapada archetype carries: mystical depth, capacity to handle the underworld of the psyche, oceanic patience. Themes of the deep contemplative, the figure who has gone to the bottom and surfaced, wise stillness." };
  A['vedic-revati'] = { name:'Revati (the Wealthy / Final-Star)', tradition:'Vedic nakshatra', writeup:"Twenty-seventh and final nakshatra — Pushan, the nourisher and guide of souls. Revati archetype carries: capacity for completion, the figure who closes the cycle, kindly generosity at the end. Themes of arrival, the gentle teacher, the figure who has done all the work and now offers it freely. Shadow side: the figure whose completion becomes inability to begin again." };

  global.PolymythHoroscopeArchetypes = A;

})(typeof window !== 'undefined' ? window : this);
